import { useState } from "react";
import styles from "../styles/Signup.module.css";

export default function BusinessInfo() {
  const [formData, setFormData] = useState({});

  const handleChange = (e) => {
    const { name, value, type, checked } = e.target;

    setFormData({
      ...formData,
      [name]: type === "checkbox" ? checked : value,
    });
  };

  const handleSubmit = (e) => {
    e.preventDefault();

    console.log("Submitted Data:", formData);

    alert("Form Submitted Successfully!");
  };

  return (
    <div className={styles.businessContainer}>
      <div className={styles.businessCard}>
        <h2 className={styles.businessTitle}>Business Information Form</h2>
        <p className={styles.businessSubtitle}>
          Lorem Ipsum is simply dummy text of the printing
        </p>

        <form onSubmit={handleSubmit}>
          <div className={styles.businessGrid}>
            <input
              type="text"
              placeholder="Full Name"
              name="fullName"
              className={`${styles.businessInput} ${styles.fullWidth}`}
              onChange={handleChange}
            />

            <input
              type="text"
              placeholder="Business Name"
              name="businessName"
              className={styles.businessInput}
              onChange={handleChange}
            />

            <select
              name="segment"
              className={styles.businessInput}
              onChange={handleChange}
            >
              <option value="">Business Segment</option>
              <option value="Retail">Retail</option>
              <option value="Manufacturing">Manufacturing</option>
              <option value="Service">Service</option>
            </select>

            <input
              type="text"
              placeholder="Description"
              name="description"
              className={`${styles.businessInput} ${styles.fullWidth}`}
              onChange={handleChange}
            />

            <input
              type="text"
              placeholder="Address 1"
              name="address1"
              className={styles.businessInput}
              onChange={handleChange}
            />

            <input
              type="text"
              placeholder="Address 2"
              name="address2"
              className={styles.businessInput}
              onChange={handleChange}
            />

            <div className={`${styles.row} ${styles.fullWidth}`}>
              <input
                type="text"
                placeholder="City"
                name="city"
                className={styles.smallInput}
                onChange={handleChange}
              />
              <select
                name="state"
                className={styles.smallInput}
                onChange={handleChange}
              >
                <option value="">State</option>
                <option value="Maharashtra">Maharashtra</option>
                <option value="Delhi">Delhi</option>
              </select>
              <input
                type="text"
                placeholder="Country"
                name="country"
                className={styles.smallInput}
                onChange={handleChange}
              />
            </div>

            {/* Pin & Location */}
            <div className={`${styles.row} ${styles.fullWidth}`}>
              <input
                type="text"
                placeholder="Pin"
                name="pin"
                className={styles.pinInput}
                onChange={handleChange}
              />

              <div className={styles.locationWrapper}>
                <input
                  type="text"
                  placeholder="Location url"
                  name="location"
                  className={styles.locationInput}
                  onChange={handleChange}
                />
                <span className={styles.mapLink}>Open Google Map ↗</span>
              </div>
            </div>

            <input
              type="text"
              placeholder="Business PAN"
              name="pan"
              className={styles.businessInput}
              onChange={handleChange}
            />

            <input
              type="text"
              placeholder="Business GST"
              name="gst"
              className={styles.businessInput}
              onChange={handleChange}
            />

            <div className={`${styles.fullWidth} ${styles.checkboxRow}`}>
              <input type="checkbox" name="agree" onChange={handleChange} />
              <span>
                Lorem Ipsum is simply dummy text of the printing and typesetting
                industry.
              </span>
            </div>

            <div className={`${styles.fullWidth} ${styles.center}`}>
              <button type="submit" className={styles.submitBtn}>
                SUBMIT
              </button>
            </div>
          </div>
        </form>
      </div>
    </div>
  );
}
